import{_ as a,o as e,c as p,j as r,a as t,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"游星骑兵","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/6.套装/游星骑兵.md","filePath":"4.资源分区/7.物品与装备/6.套装/游星骑兵.md"}'),n={name:"4.资源分区/7.物品与装备/6.套装/游星骑兵.md"};function o(d,b,_,l,i,c){return e(),p("div",null,[...b[0]||(b[0]=[r("h1",{id:"游星骑兵",tabindex:"-1"},[t("游星骑兵 "),r("a",{class:"header-anchor",href:"#游星骑兵","aria-label":'Permalink to "游星骑兵"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调017")])])],-1),s('<h1 id="游星骑兵-1" tabindex="-1">游星骑兵 <a class="header-anchor" href="#游星骑兵-1" aria-label="Permalink to &quot;游星骑兵&quot;">​</a></h1><p>游星骑兵：<br> 一位工匠锻造的一套骑士装备，出于锻造者自身的爱好，他的作品往往以星辰为名字。</p><p>燃烧的灾厄-天狼<br> C+1000<br> 特异本质<br> 在我们的星球上天狼星是观测时夜空中最亮的恒星，工匠在锻造这把武器时将“光芒”与“烧焦”的概念融入其中，构成了一把突破前路的兵刃。<br> 其外表为一柄单尖两刃，金属长柄的的长枪。枪头为精炼陨铁辅以特殊的燃烧工艺，强化了撕裂目标的穿透能力与熔炼目标的烧却能力；枪柄以丝金与其他金属融合，使其获得能具使用者要求变化柔韧与坚硬程度的能力。<br> 【骑士啊，我将为你铸起锋刃，前路无障】</p><p>武器类型：长枪<br> 武器基本属性：武器伤害9L，高速5，体积4<br> 武器特殊属性：【长柄】【双手】【格挡2】<br> 【焦灼之星】：传言中有毁灭力量的破坏之星，拥有着燃烧的伟力。以一个自由动作消耗2点能量来启动/维持一轮，枪尖将被点燃，在攻击时将会持续的灼烧目标，你的每次攻击都会附带1点燃烧点数。<br> 【炎星耀升】：随着时间的推移，天狼将会更加耀眼，当你经历一场影片后，焦灼之星提供的1点燃烧点数将进化为1点不可豁免的燃烧点数。</p><p>【灾星天狼】：当敌人人数大于等于己方时，天狼将更加地兴奋，它是象征着野心，勇气与决心的灾厄之星，它会主动释放自己的力量，帮助使用者更好地进攻，更好地摧毁目标，你的攻击可以结合入移动之中。<br> 当单体敌人力量强大时（精英怪及以上），天狼将咆哮，它会吞噬使用者的体力，以此更好地撕裂目标。自主选择启动，对自身造成2点不可豁免的严重伤害，这场战斗中，自身的攻击获得3点气势加成。<br> 当没有过于强大的单体敌人，但为战争场景时，也可以触发2效果。</p><p>恒古的不移-北辰<br> C+1000<br> 特异本质<br> 在我们的星球上观测北极星（北辰）的位置几乎恒古不变，工匠将这份坚定，执着和永远的守护融入锻造之中，构造出一面不会偏移的庇护。<br> 其本身是一面模块化的分体盾牌。其核心为一块金属护臂-北极，辅以核心周身的七块分体元件-北斗七星。通过能量操控分体元件的移动，以此能够达成不同的防御效果。<br> 【骑士啊，我将为你抵起障壁，前路无碍】</p><p>武器类型：盾牌/重盾<br> 武器基本属性：武器伤害3L<br> 体积：4<br> 武器特殊属性：【双手】【格挡10】【全能量抗力1】<br> 使用一个迅捷动作消耗3点能量在当前场景中激活北辰的真正力量，激活后才能获得后续的特性。<br> 【不变之星】：这面盾牌能够帮你抵挡伤害，即使你没正面躲在齐后，它也能通过立场帮你抵御，使用者获得【防弹】，这面盾牌将自动清洁不会沾染污渍。<br> 【恒星稳固】：随着时间的推移，北辰将愈发地稳固，当你经历1场影片后，额外获得【防能量】。<br> 【不移北辰】：北辰形态将会转变为以下两种之一，选择形态后，每回合一次，你可以用一个自由动作不消耗能量转变形态。<br> 坚盾模式：以护臂北极为核心，其他七块分件将有序排列，层叠组合出一块锥形的盾牌，其本身坚固无比，为你提供3DR/钝击的伤害防御。<br> 偏斜模式：以护臂北极为核心，其他七块分件将通过内部能量悬浮，并在每块分件之间勾结立场，制造出偏斜护盾。它将为你提供全能量抗力提升1点的效果。</p><p>全方的调和-毕宿五<br> C+1000<br> 特异本质<br> 在我们的星球上毕宿五是最容易找到的星系，在某些文化里有毕宿五为主星伴随其周遭四颗恒星象征东南西北与中央，工匠将其内外兼具的全面融入制作之中，凝练成了一身协调全身的衣装。<br> 其本身是一条轻便的腰带，在激活后，将内部虚数空间的装甲部件投影凝聚，装甲将即为快速在使用者身影轮廓聚拢，凝结。<br> 着装状态下，装甲具有典型金属质感，通体银白，各部位连接处用灿金色底边勾勒，肩甲与腿甲棱角分明，部分位置点缀星图与金色镶边。为使用者提供全方面防护。<br> 【骑士啊，我将为你穿着甲胄，前路无惧】</p><p>护甲类型：重甲<br> 护甲基本属性：10/10 【盔甲减值2】【封闭3】<br> 护甲穿着/启动：通过一个自由动作触碰腰带并完成身份认证（只有购买者能使用这套装甲），之后装甲将会展开并迅速自动穿着于使用者身上，持续一场景。装甲的所有属性如无特殊描写，均需要在展开穿着后生效。<br> 【追随之星】：作为内外兼具的装甲，无论展开与否，它都能为装备者调和生存状态，展开最基础的环境防护，获得【三防】。<br> 【调和曲调】：随着时间的推移，毕宿五能够更好地调节自身，当你经历一场影片后，抵消2点盔甲减值，获得2点抵破甲。<br> 【全方的毕宿五】：毕宿五的内置系统将会在能源充足的情况下，持续性为使用者提供防护。使用者可以以一个自由动作能量，在自身周围展开1护盾（视为防御附加成功），不可叠加，持续一轮。</p><p>勇气的开拓-南十字<br> 特异本质<br> 在我们的星球上南十字星探索的导航与信标，工匠将这份方位的指引与开拓的勇气融入大胆的妄想中，构想出了一匹不会迷惘的伙伴。<br> 其本身是一枚同时兼具指引与记时的指针（罗盘/怀表），激活后将联动虚数能量与使用者的精神，凝聚出一匹由黑色金属构成的机械战马，作为伙伴它将为你导航并载你前行。<br> 【骑士啊，我将为你启明道标，前路无忧】<br> C+2000<br> 类型：轻型载具<br> 体积：8<br> 结构值：36<br> 装甲：20<br> 速度：60米<br> 最高速：120米<br> 加速度：15米<br> 载员：骑乘位1人，乘坐位1人，最多载荷人数2，最大载荷体积12<br> 智能情况：南十字搭载了智能学习的高级AI，在没有使用者指令的情况下，也能自由行动，只能判断当前情况进行移动。</p><p>载具形态：南十字将会有两种模式：旅途形态与骑乘形态，两种形态结构值共享。形态的转变需要载具自己消耗一个标准动作。<br> 旅途形态：将会解除武装，只保留最基本的护甲（轻型载具模板将生效），防御减半，最终移动速度加倍，最高速与加速度分别提升至240米与30米。<br> 骑乘形态：会保持武装（轻型载具模板不生效），这个形态下，载具可代替驾驶者本身的移动方式结合在正常冲锋攻击。</p><p>画风：南十字本身为一块指针罗盘,在进入影片后，你可以通过一个自由动作激活罗盘，以此唤醒南十字星。这时的南十字没有碰撞体积，本体依旧呆在罗盘里。你可以通过一个移动动作使其变为实体。<br> 在战斗状态时，你可以花费自己一整个回合来使南十字变为实体，骑上南十字需要花费一个迅捷动作。<br> 南十字在奔跑时，能够根据驾驶者的主要伤害类型来产生一定的视觉特效。比如使用者的主要伤害为火焰，南十字的跑动将伴随火焰，但这只是视觉特效，不能产生任何实质效果。<br> 【航行准备】：南十字作为冒险的伙伴，在设计之初用特殊科技制造了一枚核心，其连通一个独立的小型空间，大小为3立方米，同时里面会保存生存物资：可以持续生产食物与水源，每天能稳定生产2人份健康生活的美味食物与水源。<br> 【指引之星】：南十字星将会伴随左右，帮助你征服险恶的地形，指明前进的道路。为你提供D级信息共享与C级的困难地形免疫，信息共享基于电子设备，但无需网络。<br> 【开拓之旅】：随着时间的推移，南十字能收集过往的探索数据，帮助之后更好的开拓，当你经历一场影片后【指引之星】的D级信息共享升级为C级，C级的困难地形免疫升级为B级。</p><p>【勇气的南十字】：探索天空是一件需要莫大勇气的事情，现在你有了这么个机会，南十字有着普通飞行能力。当使用者自己也有飞行能力时，南十字的飞行等级将变成二者中高的那一个，但这需要支付1D+500分来额外开启，不会因此获得自由属性。</p><p>套装效果：<br> 只有同时持有【燃烧的灾厄-天狼】与【恒古的不移-北辰】时才能触发2件套效果：<br> 【枪与盾的奏舞】：你可以以一个移动动作支付1点意志力将两件装备结合，展开成为新的装备，同时获得以下两种模式的效果。</p><p>灼热闪耀天狼：北辰的七块分体将自带解体，重新覆盖在天狼上，此时的天狼将从长枪转变为骑枪（依旧用长枪专业），进攻能力进一步强化。<br> 武器伤害提升3L，天狼额外获得5点破甲。</p><p>恒净不移北辰：天狼的能量将会大幅传输到北辰上，使得北辰额外投影出更多的分体碎片，防护能力进一步强化。<br> 原先的坚盾模式与偏斜模式能够同时共存，你的意志、强韧、反射豁免检定各+5器械加值，同时盾牌的格挡防御提升2点。</p><p>当持有四件套时，在二件套的基础上额外获得：<br> 冲锋时，你的基础防御不承受减值 ，如果你已经拥有此效果，则改为仅在冲锋攻击时可获得5点洞察加值<br> 【全方的调和-毕宿五】的效果【全方的毕宿五】获得强化在自由动作额外再多消耗1点能量，使获得的护盾（防御附加）额外提升2点。</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',19)])])}const f=a(n,[["render",o]]);export{m as __pageData,f as default};
